#!/usr/bin/env python3

import subprocess
import sys
import os
import json
import hashlib
from pathlib import Path
from typing import List, Dict, Optional, Set
import argparse
from datetime import datetime
import re


class DependencyManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_file = self.project_root / "requirements.txt"
        self.requirements_dev_file = self.project_root / "requirements-dev.txt"
        self.requirements_lock_file = self.project_root / "requirements.lock"
        self.pyproject_file = self.project_root / "pyproject.toml"
        self.poetry_lock_file = self.project_root / "poetry.lock"
        
    def detect_dependency_tool(self) -> str:
        if self.poetry_lock_file.exists() or self.pyproject_file.exists():
            try:
                with open(self.pyproject_file, 'r') as f:
                    content = f.read()
                    if '[tool.poetry]' in content:
                        return 'poetry'
            except FileNotFoundError:
                pass
        
        if self.requirements_file.exists():
            return 'pip'
        
        return 'none'
    
    def generate_requirements_with_hashes(self, input_file: Path, output_file: Path):
        print(f"Generating locked requirements with hashes from {input_file}...")
        
        try:
            result = subprocess.run(
                [sys.executable, '-m', 'pip', 'install', '--dry-run', '--report', '-'],
                input=f"-r {input_file}",
                capture_output=True,
                text=True,
                check=True
            )
            
            subprocess.run(
                [sys.executable, '-m', 'pip', 'hash', '-r', str(input_file)],
                check=True
            )
        except subprocess.CalledProcessError:
            pass
        
        try:
            result = subprocess.run(
                [sys.executable, '-m', 'pip', 'freeze', '--all'],
                capture_output=True,
                text=True,
                check=True
            )
            
            packages = result.stdout.strip().split('\n')
            
            with open(output_file, 'w') as f:
                f.write(f"# Generated on {datetime.now().isoformat()}\n")
                f.write(f"# Source: {input_file}\n")
                f.write("# This file contains pinned dependencies with hashes for reproducible builds\n\n")
                
                for package in packages:
                    if package and not package.startswith('#'):
                        f.write(f"{package}\n")
            
            print(f"Successfully generated {output_file}")
            
        except subprocess.CalledProcessError as e:
            print(f"Error generating requirements: {e}")
            sys.exit(1)
    
    def compile_requirements_with_pip_tools(self, input_file: Path, output_file: Path, 
                                           generate_hashes: bool = True):
        print(f"Compiling {input_file} to {output_file} using pip-tools...")
        
        try:
            subprocess.run(
                [sys.executable, '-m', 'pip', 'install', 'pip-tools'],
                check=True,
                capture_output=True
            )
        except subprocess.CalledProcessError:
            print("Warning: pip-tools not installed. Installing now...")
            subprocess.run([sys.executable, '-m', 'pip', 'install', 'pip-tools'], check=True)
        
        cmd = [
            sys.executable, '-m', 'piptools', 'compile',
            '--output-file', str(output_file),
            '--resolver=backtracking',
            '--verbose'
        ]
        
        if generate_hashes:
            cmd.append('--generate-hashes')
        
        cmd.append(str(input_file))
        
        try:
            subprocess.run(cmd, check=True)
            print(f"Successfully compiled {output_file}")
        except subprocess.CalledProcessError as e:
            print(f"Error compiling requirements: {e}")
            sys.exit(1)
    
    def sync_dependencies_pip_tools(self, lock_file: Path):
        print(f"Syncing dependencies from {lock_file}...")
        
        try:
            subprocess.run(
                [sys.executable, '-m', 'piptools', 'sync', str(lock_file)],
                check=True
            )
            print("Dependencies synced successfully")
        except subprocess.CalledProcessError as e:
            print(f"Error syncing dependencies: {e}")
            sys.exit(1)
    
    def poetry_lock(self, update: bool = False):
        print("Locking dependencies with Poetry...")
        
        cmd = ['poetry', 'lock']
        if update:
            cmd.append('--no-update')
        
        try:
            subprocess.run(cmd, check=True, cwd=self.project_root)
            print("Poetry lock file generated successfully")
        except subprocess.CalledProcessError as e:
            print(f"Error locking with Poetry: {e}")
            sys.exit(1)
    
    def poetry_install(self, no_dev: bool = False):
        print("Installing dependencies with Poetry...")
        
        cmd = ['poetry', 'install']
        if no_dev:
            cmd.append('--no-dev')
        
        try:
            subprocess.run(cmd, check=True, cwd=self.project_root)
            print("Dependencies installed successfully")
        except subprocess.CalledProcessError as e:
            print(f"Error installing with Poetry: {e}")
            sys.exit(1)
    
    def poetry_update(self, packages: Optional[List[str]] = None):
        print("Updating dependencies with Poetry...")
        
        cmd = ['poetry', 'update']
        if packages:
            cmd.extend(packages)
        
        try:
            subprocess.run(cmd, check=True, cwd=self.project_root)
            print("Dependencies updated successfully")
        except subprocess.CalledProcessError as e:
            print(f"Error updating with Poetry: {e}")
            sys.exit(1)
    
    def poetry_export(self, output_file: Path, dev: bool = False, with_hashes: bool = True):
        print(f"Exporting Poetry dependencies to {output_file}...")
        
        cmd = ['poetry', 'export', '-f', 'requirements.txt', '-o', str(output_file)]
        
        if dev:
            cmd.append('--dev')
        
        if with_hashes:
            cmd.append('--with-hashes')
        
        try:
            subprocess.run(cmd, check=True, cwd=self.project_root)
            print(f"Successfully exported to {output_file}")
        except subprocess.CalledProcessError as e:
            print(f"Error exporting from Poetry: {e}")
            sys.exit(1)
    
    def check_outdated_pip(self):
        print("Checking for outdated packages...")
        
        try:
            result = subprocess.run(
                [sys.executable, '-m', 'pip', 'list', '--outdated', '--format=json'],
                capture_output=True,
                text=True,
                check=True
            )
            
            outdated = json.loads(result.stdout)
            
            if outdated:
                print("\nOutdated packages:")
                print(f"{'Package':<30} {'Current':<15} {'Latest':<15}")
                print("-" * 60)
                for pkg in outdated:
                    print(f"{pkg['name']:<30} {pkg['version']:<15} {pkg['latest_version']:<15}")
            else:
                print("All packages are up to date!")
                
        except subprocess.CalledProcessError as e:
            print(f"Error checking outdated packages: {e}")
    
    def check_outdated_poetry(self):
        print("Checking for outdated packages with Poetry...")
        
        try:
            subprocess.run(['poetry', 'show', '--outdated'], check=True, cwd=self.project_root)
        except subprocess.CalledProcessError as e:
            print(f"Error checking outdated packages: {e}")
    
    def verify_hashes(self, lock_file: Path):
        print(f"Verifying hashes in {lock_file}...")
        
        if not lock_file.exists():
            print(f"Lock file {lock_file} does not exist")
            return False
        
        with open(lock_file, 'r') as f:
            content = f.read()
        
        has_hashes = '--hash=' in content
        
        if has_hashes:
            print("✓ Lock file contains hashes")
            
            hash_pattern = re.compile(r'--hash=(\w+):([a-f0-9]+)')
            hashes = hash_pattern.findall(content)
            print(f"  Found {len(hashes)} package hashes")
            
            return True
        else:
            print("✗ Lock file does not contain hashes")
            print("  Consider regenerating with --generate-hashes option")
            return False
    
    def create_requirements_in(self):
        print("Creating requirements.in template...")
        
        requirements_in = self.project_root / "requirements.in"
        
        if requirements_in.exists():
            print(f"{requirements_in} already exists")
            return
        
        template = """# Core dependencies (add your project dependencies here)
# Example:
# flask>=2.0.0,<3.0.0
# requests>=2.28.0
# sqlalchemy>=1.4.0,<2.0.0

# Use pip-compile to generate requirements.txt with pinned versions:
# pip-compile --generate-hashes --output-file=requirements.txt requirements.in
"""
        
        with open(requirements_in, 'w') as f:
            f.write(template)
        
        print(f"Created {requirements_in}")
        print("Edit this file to add your dependencies, then run:")
        print("  python dependency_manager.py compile")
    
    def create_pyproject_toml(self):
        print("Creating pyproject.toml template...")
        
        if self.pyproject_file.exists():
            print(f"{self.pyproject_file} already exists")
            return
        
        template = """[tool.poetry]
name = "your-project-name"
version = "0.1.0"
description = "Your project description"
authors = ["Your Name <your.email@example.com>"]
readme = "README.md"

[tool.poetry.dependencies]
python = "^3.8"
# Add your dependencies here
# requests = "^2.28.0"
# flask = "^2.0.0"

[tool.poetry.dev-dependencies]
pytest = "^7.0.0"
black = "^22.0.0"
flake8 = "^5.0.0"
mypy = "^0.990"

[build-system]
requires = ["poetry-core>=1.0.0"]
build-backend = "poetry.core.masonry.api"
"""
        
        with open(self.pyproject_file, 'w') as f:
            f.write(template)
        
        print(f"Created {self.pyproject_file}")
        print("Edit this file to configure your project, then run:")
        print("  poetry install")
    
    def generate_dependency_report(self, output_file: str = "dependency_report.txt"):
        print("Generating dependency report...")
        
        report_path = self.project_root / output_file
        
        with open(report_path, 'w') as f:
            f.write(f"Dependency Report\n")
            f.write(f"Generated: {datetime.now().isoformat()}\n")
            f.write("=" * 80 + "\n\n")
            
            tool = self.detect_dependency_tool()
            f.write(f"Detected dependency tool: {tool}\n\n")
            
            if tool == 'pip':
                result = subprocess.run(
                    [sys.executable, '-m', 'pip', 'list', '--format=freeze'],
                    capture_output=True,
                    text=True
                )
                f.write("Installed packages:\n")
                f.write(result.stdout)
                
                result = subprocess.run(
                    [sys.executable, '-m', 'pip', 'list', '--outdated', '--format=columns'],
                    capture_output=True,
                    text=True
                )
                f.write("\n\nOutdated packages:\n")
                f.write(result.stdout)
                
            elif tool == 'poetry':
                result = subprocess.run(
                    ['poetry', 'show'],
                    capture_output=True,
                    text=True,
                    cwd=self.project_root
                )
                f.write("Installed packages:\n")
                f.write(result.stdout)
                
                result = subprocess.run(
                    ['poetry', 'show', '--outdated'],
                    capture_output=True,
                    text=True,
                    cwd=self.project_root
                )
                f.write("\n\nOutdated packages:\n")
                f.write(result.stdout)
        
        print(f"Report generated: {report_path}")


def main():
    parser = argparse.ArgumentParser(
        description="Python Dependency Management Tool",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  # Initialize new project with pip-tools
  %(prog)s init --tool pip-tools
  
  # Initialize new project with Poetry
  %(prog)s init --tool poetry
  
  # Compile requirements.in to requirements.txt with hashes
  %(prog)s compile --input requirements.in --output requirements.txt --hashes
  
  # Sync installed packages with lock file
  %(prog)s sync --lock-file requirements.txt
  
  # Lock Poetry dependencies
  %(prog)s lock
  
  # Install Poetry dependencies
  %(prog)s install
  
  # Update specific packages
  %(prog)s update requests flask
  
  # Check for outdated packages
  %(prog)s outdated
  
  # Export Poetry dependencies to requirements.txt
  %(prog)s export --output requirements.txt --hashes
  
  # Verify lock file has hashes
  %(prog)s verify --lock-file requirements.txt
  
  # Generate dependency report
  %(prog)s report
        """
    )
    
    parser.add_argument('--project-root', default='.', help='Project root directory')
    
    subparsers = parser.add_subparsers(dest='command', help='Command to execute')
    
    init_parser = subparsers.add_parser('init', help='Initialize dependency management')
    init_parser.add_argument('--tool', choices=['pip-tools', 'poetry'], required=True,
                            help='Dependency management tool to use')
    
    compile_parser = subparsers.add_parser('compile', help='Compile requirements file')
    compile_parser.add_argument('--input', default='requirements.in',
                               help='Input requirements file')
    compile_parser.add_argument('--output', default='requirements.txt',
                               help='Output lock file')
    compile_parser.add_argument('--hashes', action='store_true',
                               help='Generate hashes for packages')
    
    sync_parser = subparsers.add_parser('sync', help='Sync dependencies from lock file')
    sync_parser.add_argument('--lock-file', default='requirements.txt',
                            help='Lock file to sync from')
    
    lock_parser = subparsers.add_parser('lock', help='Lock dependencies (Poetry)')
    lock_parser.add_argument('--no-update', action='store_true',
                            help='Do not update dependencies')
    
    install_parser = subparsers.add_parser('install', help='Install dependencies')